#include "max30105.h"
#include <Wire.h>
#include <MAX30105.h>
static MAX30105 pox;
static uint32_t _red=0,_ir=0,_green=0;static float _t=0;static unsigned long _l=0;
void max30105_setup(){Wire.begin();if(!pox.begin(Wire,I2C_SPEED_FAST)){Serial.println("[max30105] Fail!");return;}pox.setup();pox.setPulseAmplitudeRed(0x0A);pox.setPulseAmplitudeGreen(0);Serial.println("[max30105] OK");}
void max30105_loop(){if(millis()-_l<50)return;_l=millis();_red=pox.getRed();_ir=pox.getIR();_green=pox.getGreen();_t=pox.readTemperature();}
uint32_t max30105_get_red(){return _red;}
uint32_t max30105_get_ir(){return _ir;}
uint32_t max30105_get_green(){return _green;}
float max30105_get_temperature(){return _t;}
